    signal = np.sin(2 * np.pi * f1 * t) + np.sin(2 * np.pi * f2 * t)
    freqs = np.fft.rfftfreq(N, 1 / sr)
    mags = np.abs(np.fft.rfft(signal)) * 2 / N

